1	import { readFileSync } from "node:fs";
2	import { quote, claim } from "./claim-office.js";
3	
4	type Step = any;
5	
6	const KNOWN_ITEM_TYPES = ["sword", "amulet", "staff", "potion", "rune", "moonstone"];
7	
8	function validateItems(items: Step[]): void {
9	  for (const item of items) {
10	    if (!KNOWN_ITEM_TYPES.includes(item.type)) {
11	      throw new Error(`Unknown item type: ${item.type}`);
12	    }
13	  }
14	}
15	
16	function executeQuote(step: Step, years: number): any {
17	  validateItems(step.items);
18	  return quote({ items: step.items, years, priorContract: false });
19	}
20	
21	function executeClaim(step: Step, steps: Step[]): any {
22	  const referencedQuote = steps[step.policy];
23	  const policyItemTypes = referencedQuote.items.map((i: any) => i.type);
24	  for (const damage of step.incident.damages) {
25	    if (!policyItemTypes.includes(damage.itemType)) {
26	      throw new Error(`Damage references item not in policy: ${damage.itemType}`);
27	    }
28	  }
29	  return claim({ policy: { items: referencedQuote.items }, incident: step.incident });
30	}
31	
32	function executeStep(step: Step, steps: Step[], years: number): any {
33	  if (step.op === "claim") {
34	    return executeClaim(step, steps);
35	  }
36	  return executeQuote(step, years);
37	}
38	
39	try {
40	  const scenario = JSON.parse(readFileSync(0, "utf-8"));
41	  const years = scenario.customer.yearsWithMHPCO;
42	  const steps: Step[] = scenario.steps;
43	  const results = steps.map((step) => executeStep(step, steps, years));
44	  process.stdout.write(JSON.stringify({ results }));
45	} catch (e: any) {
46	  process.stderr.write(`Error: ${e.message}\n`);
47	  process.exit(1);
48	}
